mapper.select:
    	SELECT COUNT(*) AS CNT
		FROM GLB_ATM_MGT G
		WHERE 1 = 1

	     	AND UPPER(G.CHNNL_ADDR) LIKE UPPER('%' || #{keyWord} || '%')


	     	AND G.NTNL LIKE #{ntnl}


	     	AND G.CITY LIKE #{city}


	     	AND G.LOCAL LIKE #{local}

	    WITH UR

SELECT SERNO , ACCT_TBL , CHNNL_MK , CHNNL_NM , CHNNL_ADDR , CNTCT_PLCE , OP_TM , ROW_NUMBER() OVER(ORDER BY SERNO ASC) RN FROM GLB_ATM_MGT G WHERE 1 = 1
AND UPPER(G.CHNNL_ADDR) LIKE UPPER('%' || #{keyWord} || '%')
AND G.NTNL LIKE #{ntnl}
AND G.CITY LIKE #{city}
AND G.LOCAL LIKE #{local}
WITH UR
